"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[3645],{1909:(e,t,i)=>{i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>o,default:()=>d,frontMatter:()=>a,metadata:()=>s,toc:()=>h});var n=i(4848),r=i(8453);const a={},o="Data Phenotype & Chart Review SOP",s={id:"Chart-Review/Chart-Review",title:"Data Phenotype & Chart Review SOP",description:"A. Purpose ##",source:"@site/docs/Chart-Review/Chart-Review.mdx",sourceDirName:"Chart-Review",slug:"/Chart-Review/",permalink:"/Chorus_SOP/docs/Chart-Review/",draft:!1,unlisted:!1,editUrl:"https://github.com/chorus-ai/Chorus_SOP/edit/review/sop-website/docs/Chart-Review/Chart-Review.mdx",tags:[],version:"current",lastUpdatedBy:"Polina Talapova",lastUpdatedAt:1777385474,formattedLastUpdatedAt:"Apr 28, 2026",frontMatter:{},sidebar:"sopSidebar",previous:{title:"Chart Review",permalink:"/Chorus_SOP/docs/category/chart-review"},next:{title:"Common Data Elements",permalink:"/Chorus_SOP/docs/category/common-data-elements"}},c={},h=[{value:"A. Purpose",id:"a-purpose",level:2},{value:"B. Scope",id:"b-scope",level:2},{value:"C. Definitiions",id:"c-definitiions",level:2},{value:"D. Responsibilities",id:"d-responsibilities",level:2},{value:"E. Procedure",id:"e-procedure",level:2},{value:"F. Reporting and Publication",id:"f-reporting-and-publication",level:2},{value:"G. References",id:"g-references",level:2},{value:"H. Workflow",id:"h-workflow",level:2}];function l(e){const t={a:"a",h1:"h1",h2:"h2",img:"img",p:"p",strong:"strong",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.h1,{id:"data-phenotype--chart-review-sop",children:"Data Phenotype & Chart Review SOP"}),"\n",(0,n.jsx)(t.h2,{id:"a-purpose",children:"A. Purpose"}),"\n",(0,n.jsx)(t.p,{children:"To provide a standardized approach for conducting a chart review to ensure data accuracy, consistency in documentation to achieve identification of surrogative label (silver label) for machine learning-driven research for the Patient-Focused Collaborative Hospital Repository Uniting Standards for Equitable AI (thereafter CHoRUS) members."}),"\n",(0,n.jsx)(t.h2,{id:"b-scope",children:"B. Scope"}),"\n",(0,n.jsx)(t.p,{children:"This SOP applies to all clinicians and research assistants who will be involved in the chart review process."}),"\n",(0,n.jsx)(t.h2,{id:"c-definitiions",children:"C. Definitiions"}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Chart Review"}),": The process of examining a patient's medical record for relevant infomration."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"EHR (Electonic Health Record)"}),": Digital version of a patient's paper chart, which contaiins medical history, diagnoses, treatment plans, immunization dates, allergies, radiology images, and lab/test result."]}),"\n",(0,n.jsx)(t.h2,{id:"d-responsibilities",children:"D. Responsibilities"}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Chart Reviewer (CR)"}),": Responsible for accessing, reviewing, and accurately recording information from patient charts as per this SOP. Reviewers should have critical care work experience (actual patient care in the intensive care unit or equivalent space in hospital) and will be limited to individual with medical (M.D or equivalent) degree or nursing/PA degree (R.N. or eq) for current round."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Point Person (PP)"}),": A member of CHoRUS, designated by the individual site PI to direct the review process. He or she is responsible for the pre-review training of all chart reviewers and supervision of the quality of the results from the chart review. The PP also is responsible for the reporting spreadsheet generation and act as a point person for the institution."]}),"\n",(0,n.jsx)(t.h2,{id:"e-procedure",children:"E. Procedure"}),"\n",(0,n.jsx)(t.p,{children:"E.1. Numbers of charts to be reviewed:\nA total of 10% of all charts submitted to CHoRUS central (at least 200+ charts per center) will be reviewed for 8 different concept labels, to identify and ascertain the existence of concept in EHR."}),"\n",(0,n.jsx)(t.p,{children:"The pilot stage will consist of reviewing 20 charts - each covered by two (2) CRs. The very first 5 charts by two CRs will not be counted towards the statistics (which leaves 15 charts to be included in the final analysis) but to be used for other internal review."}),"\n",(0,n.jsx)(t.p,{children:"The next 15 charts after the first 5 charts will also be read by two (2) CRs. This will allow the calculation of interrater reliability (IRR) by Data Annotation Team. Interim decision will be made by the Team when and how to proceed. If IRR is within reasonable level, the rest of charts will be read by 1 CR per chart. Otherwise, the DA team will determine whether more charts need to be annotated by 2 CRs per chart."}),"\n",(0,n.jsx)(t.p,{children:"E.2. The RedCap Survey Preparation"}),"\n",(0,n.jsx)(t.p,{children:"a. Upon receiving research identifiers (study_id and visit_occurrence) from the CHORUS DA team, each center should map these identifiers to actual EHR identifiers. Depending on center's policy or availability, this process can be done either with honest broker or a designated researcher."}),"\n",(0,n.jsx)(t.p,{children:"b. The list of both research and EHR identifiers should be given to CRs at the center."}),"\n",(0,n.jsx)(t.p,{children:"c. The CR identify those patients using the individual center's EHR. If CR cannot identify for any reason, CR needs to report PP, who will then report to CHORUS DA team to issue more research identifiers from the enriched cohorts."}),"\n",(0,n.jsx)(t.p,{children:"d. The CR needs to have enough time spared at least to go through the single chart. We recommend having approximately 60 minutes time window for the first chart review."}),"\n",(0,n.jsx)(t.p,{children:"e. Please prepare a pen and a paper to write down."}),"\n",(0,n.jsx)(t.p,{children:"E.3. The RedCap Review Protocol"}),"\n",(0,n.jsxs)(t.p,{children:["a. The PP accesses the redcap survey page (with the application through the University of Pittsburgh RedCap system: ",(0,n.jsx)(t.a,{href:"https://redcap-std.hs.pitt.edu/redcap/surveys/?s=injPIG",children:"https://redcap-std.hs.pitt.edu/redcap/surveys/?s=injPIG"}),")."]}),"\n",(0,n.jsx)(t.p,{children:"b. The PP reviews the RedCap questions and familiarize the path."}),"\n",(0,n.jsx)(t.p,{children:"c. The PP selects CRs and educate the survey response process. A few important teaching points are as follows:"}),"\n",(0,n.jsx)(t.p,{children:"i) Time to event documentation and calculation: Note that direct record of admission date based on EHR is not permitted in this research survey with privacy concern. Initially, you will be asked to log the time of admission only (please note the admission date on a paper). For example, if your patient was admitted on Feb-15 at 2300, you will not be permitted to write Feb-15. However, you will be asked to write the hours (i.e. 2300). Throughout the survey, when prompted to count the days since admission, you enter 'the day since admission'. This is a calendar day. For example, if the first evidence of sepsis occurred on Feb-16 at 0500 on the patient admitted on Feb-15 at 2300, you will write day 1 of admission (16-15=1). Then you are asked to write the time of 0500 as it was seen in EHR. (For your reference, at the end of the survey, the algorithm will subtract 2300-0500=1800, which will be applied to 2400-1800 to result in 0600 hours of delta value)"}),"\n",(0,n.jsx)(t.p,{children:"ii) Use of the MedCalc: While the use of online calculator could be cumbersome, we found that some centers do not have automated calculation of some scoring metrics, including SOFA score. Given that, when and if there is no automated calculation available from your institution EHR, we recommend using the MedCalc - for which case, there is a link to MedCalc on each question that requires complex calculation."}),"\n",(0,n.jsx)(t.p,{children:"iii) There might be some questions that you simply do not have an answer, or not applicable to your patient. In that case, please leave the answer blank - which will be a flag for us to review to identify any major systematic flaws."}),"\n",(0,n.jsx)(t.p,{children:"d. Each CR reviews 5 charts and annotate each of the concept."}),"\n",(0,n.jsx)(t.p,{children:"e. PP meets with CRs to review each concept and receives feedback to ascertain standardized workflow."}),"\n",(0,n.jsx)(t.p,{children:"f. Two CR review the next 15 charts and decide the concept presence, date and time, and the confidence of such decision (with the scale of 1 to 5, 1 being the least and 5 being the most confident). If 2 CRs have scale distance more than three (3), a third CR or PP could review the specific decision for annotation."}),"\n",(0,n.jsx)(t.p,{children:"g. We encourage the initially assigned CRs to do the entire chart review, if possible (to minimize repetitive training and utilize learning curves), but partial review with change in CR could be possible under PP's supervision for quality assurance."}),"\n",(0,n.jsx)(t.p,{children:"h. The PP can gather the conclusions of the survey. The contents include the answers for each element, decision on the concept, the confidence (scaled by CR) for each concept, and time spent for the entire survey (note the time spent will not be visible to the CRs)."}),"\n",(0,n.jsx)(t.p,{children:"E.3. Available CHoRUS Support"}),"\n",(0,n.jsx)(t.p,{children:"a. CHoRUS Data Phenotyping Team will hold an office hour at the start of the weekly Data Acquisition Team meeting (usually every Tuesday 2-3PM EST) for 10-15 minutes."}),"\n",(0,n.jsx)(t.p,{children:"b. CHoRUS Data Phenotyping Team can support individual SI through a separate meeting to check each center's progression (detailed schedule TBA)."}),"\n",(0,n.jsx)(t.h2,{id:"f-reporting-and-publication",children:"F. Reporting and Publication"}),"\n",(0,n.jsx)(t.p,{children:"The Data Phenotyping team will report to CHoRUS executive committee on its progress every 3 months. The team will remain inclusive for anyone from CHoRUS to participate with the team's work. Results and evaluation metrics, along with its downstream products will be disseminated at scientific venue or through publications. The team will abide by the authorship guideline of the CHoRUS for those activities."}),"\n",(0,n.jsx)(t.h2,{id:"g-references",children:"G. References"}),"\n",(0,n.jsx)(t.p,{children:"HIPPA Compliance Manual"}),"\n",(0,n.jsx)(t.p,{children:"Institution's EHR System Guide"}),"\n",(0,n.jsx)(t.h2,{id:"h-workflow",children:"H. Workflow"}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.img,{alt:"Chart Review Workflow Overview",src:i(9007).A+"",width:"858",height:"436"})}),"\n",(0,n.jsx)(t.p,{children:"version 1.44"}),"\n",(0,n.jsx)(t.p,{children:"Pilot 5 chart review process:\n4/15/2026\nFollowing bugs were detected and changes were made:\na) The branching logic errors including questions sep_y_v3, adhf_y_v3, and afib_y_v3 were modified. Some of the logics were deleted for clarification.\nb) The functional status questions at the end of the survey now include a new option 'patient was expired during the ICU stay' to clarify the option for those deceased and discharge was made."})]})}function d(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(l,{...e})}):l(e)}},9007:(e,t,i)=>{i.d(t,{A:()=>n});const n=i.p+"assets/images/Chart_Review_1-de2c993d9a7eacbe1988d643770c69d0.png"},8453:(e,t,i)=>{i.d(t,{R:()=>o,x:()=>s});var n=i(6540);const r={},a=n.createContext(r);function o(e){const t=n.useContext(a);return n.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:o(e.components),n.createElement(a.Provider,{value:t},e.children)}}}]);